from rest_framework import serializers
class UserCreateRequest(serializers.Serializer): email = serializers.EmailField(required=True) name = serializers.CharField(required=True, max_length=100, allow_blank=False) password = serializers.CharField(required=True, min_length=12, write_only=True)
class UserResponse(serializers.Serializer): id = serializers.IntegerField(read_only=True) email = serializers.EmailField(read_only=True) name = serializers.CharField(read_only=True) created_at = serializers.DateTimeField(read_only=True)

class UserSerializer(serializers.ModelSerializer):
    class Meta:
        model = User
        fields = "__all__"  # leaks password, is_staff, hashed_token

    def validate_email(self, value):
        if User.objects.filter(email=value).exists():  # DB query in validation
            raise serializers.ValidationError("taken")
        send_welcome_email(value)                       # business side-effect
        return value
